import React from 'react'
import { Avatar, Input } from 'antd'
import { UserOutlined } from '@ant-design/icons'
import './index.css'

export default function Login() {
  return (
    <div className='login'>
      <Avatar
        size={100}
      />
      <Input size='large'
        maxLength={10}
        style={{
          width: '200px',
          backgroundColor: "transparent",
          margin: "20px"
        }}
        prefix
        ></Input>
      <Input size='large'
        maxLength={10}
        style={{
          width: '200px',
          backgroundColor: "transparent",
          margin: "20px"
        }}></Input>
    </div>
  )
}
